head.script:
scwin.vCurDate = WebSquare.date.getCurrentServerDate("yyyyMMdd");  // 서버를 기준으로 현재 날짜 반환
scwin.vQryStDt = scwin.vCurDate.substring(0, 6) + "01";  // 조회시작일자(현재 날짜가 포함된 달의 시작 일자)
scwin.vQryEndDt = scwin.vCurDate.substring(0, 6) + new Date(scwin.vCurDate.substring(0, 4), scwin.vCurDate.substring(4, 6) , 0).getDate();  // 조회종료일자(현재 날짜가 포함된 달의 마지막 일자)

scwin.staffNo = "";
scwin.inqStDt = "";
scwin.inqEndDt = "";
scwin.lobranCd = "";
scwin.lobranNm = "";

scwin.hid_txt_inqStDt = "";
scwin.hid_txt_staffNo = "";

scwin.onpageload = function() {
    let memJson = $c.data.getMemInfo();
    console.log(memJson);
    scwin.lobranCd = memJson.lobranCd;
    scwin.lobranNm = memJson.lobranNm;

    var params = $c.data.getParameter();

    scwin.inqStDt = params.inqStDt;
    scwin.inqEndDt = params.inqEndDt;
    scwin.staffNo = params.staffNo;
};

scwin.onUdcCompleted = function() {
    // $p.setTimeout(function() {
        console.log(scwin.staffNo);
        ///임시

        ///임시
        var sEndDate = "";
        sEndDate = scwin.vQryStDt.toDate("YYYYMMDD").after(0,0,14).format("YYYYMMDD");

        if(scwin.staffNo != "" && scwin.staffNo != null){
            // ica_inqStDt.setValue(scwin.vQryStDt);
            // ica_inqEndDt.setValue(sEndDate);
            ica_inqStDt.setValue(scwin.inqStDt);
            ica_inqEndDt.setValue(scwin.inqEndDt);
            ed_staffNo.setValue(scwin.staffNo);
            scwin.f_chkOpenCommonPopUp(ed_staffNo, ed_staffNm, 1);
        } else {
            ica_inqStDt.setValue(scwin.vQryStDt);
            ica_inqEndDt.setValue(sEndDate);
        }

        $c.gus.cfEnableObj(ica_inqEndDt,false);
        ica_inqStDt.focus();
        //$c.gus.cfEnableObj(btn_Save,false);
        btn_Save.setDisabled(true);

    $p.setTimeout(function() {
        if(scwin.staffNo != "" && scwin.staffNo != null){
            scwin.f_Retrieve();
        }

    }, {"delay":500});
};


//-------------------------------------------------------------------------
// 조회
//-------------------------------------------------------------------------
scwin.f_Retrieve = async function () {  
    var chk = await $c.gus.cfValidate([condTable]);
    if (!chk){
        return;
    }

    ds_results1.removeAll();
    ds_results2.removeAll();
    ds_results3.removeAll();

    scwin.hid_txt_inqStDt = ica_inqStDt.getValue();
    scwin.hid_txt_staffNo = ed_staffNo.getValue();

    dma_search.set("inqStDt", ica_inqStDt.getValue());
    dma_search.set("inqEndDt", ica_inqEndDt.getValue());
    dma_search.set("staffNo", ed_staffNo.getValue());

    //ds_search.UseChangeInfo = false;
    $c.sbm.execute(sbm_search);

    scwin.f_buttonEnableCheck();

}

//-------------------------------------------------------------------------
// 저장
//-------------------------------------------------------------------------
scwin.f_save = async function(){
    var chk = await $c.win.confirm(MSG_CM_CRM_001);
    if(chk) {
        for(var i=0; i < ds_results3.getRowCount(); i++){
            ds_results3.setCellData(i,"stDt", scwin.hid_txt_inqStDt);
            ds_results3.setCellData(i,"staffNo", scwin.hid_txt_staffNo);
        }

        $c.sbm.execute(sbm_save);
    }
}

//-------------------------------------------------------------------------
// 팝업 처리시 검색된 데이터인 경우 팝업 처리 안함.
//-------------------------------------------------------------------------
scwin.f_chkOpenCommonPopUp = function (inObj, pairObj, disGubun, isCode) {
    // 값이 입력이 안된 경우, 해당 Text Box가 readonly 인 경우, 이전값과 동일한 경우 팝업을 실행하지 않음.
    if (!$c.gus.cfCanOpenPopup(inObj, pairObj))
        return;

    // 짝이 되는 오브젝트의 값 제거
    $c.gus.cfClearPairObj(pairObj);

    // 검색어 세팅
    var pVal = $c.gus.cfGetValue(inObj);

    // inObj가 코드 필드일 경우 팝업
    if (isCode == null || isCode == true)
        scwin.f_openCommonPopUp(disGubun, pVal, '', 'T', 'T');
    // inObj가 코드명 필드일 경우 팝업
    else
        scwin.f_openCommonPopUp(disGubun, '', pVal, 'T', 'T');
}

//-------------------------------------------------------------------------
// 공통 Popup 처리 : Gubun Code 에 따른 공통 Popup 을 호출한다.
//-------------------------------------------------------------------------
scwin.f_openCommonPopUp = async function (disGubun, pCode, pName, pClose, pAllSearch) {
    // 선언부
    var rtnList;  // 공통POP-UP -> 요청화면 
    var arrParam = new Array();

    switch (disGubun)
    {
        case 1:	

            arrParam[0] = pCode; //사번
            arrParam[1] = pName; //사원명
            arrParam[2] = scwin.lobranCd; //점소코드
            arrParam[3] = scwin.lobranNm;  //점소명
            arrParam[4] = ''; //작업장코드
            arrParam[5] = '';//직종  (정규직)
            arrParam[6] = '' //상세직종코드 (하역직)
            arrParam[7] = ''; //직급
            arrParam[8] = scwin.vCurDate;  //작업일
            arrParam[9] = ',D'; //배치가능여부
            arrParam[10] = pClose; //WINDOW CLOSE 여부
            arrParam[11] = "1"; //상세직종Flag

            //rtnList = window.showModalDialog("/ds/op/rscconfirm/manpwrrscconfirm/op_103_01_10p.jsp", arrParam, "dialogHeight:450px; dialogWidth:530px; resizable=no; help:no; status:no; center=true; "); 	

            var win_url = "/ui/ds/op/rscconfirm/manpwrrscconfirm/op_103_01_10p.xml";

            var opts = scwin.opts || {};
            opts.modal = true;
            opts.type = "browserPopup";
            opts.id = scwin.popupID || "pupup";
            opts.width = 800;
            opts.height = 530;
            opts.popupName = '인력 검색';

            rtnList = await $c.win.openPopup(win_url, opts, arrParam);
            console.log("rtnList : " , rtnList);


            //(0)직종코드		
            //(1)직종명	        
            //(2)인원번호		
            //(3)인원명	                          
            //(4)직급		    
            //(5)직급명		    
            //(6)물류점소코드   
            //(7)물류점소명		
            //(8)상세직종코드	
            //(9)상세직종명		                  
            //(10)배치가능여부	
            //(11)본사계약직여부 
            //(12)연근여부		


            //rtnList = cfCommonPopUp('retrieveOpEmpCdInfo',pCode,pName,sWinCloseTF,null,null,null,null,null,null,null,null,null); // 사원

            if (rtnList != null) {
                ed_staffNo.setValue(rtnList[2]);	//사원코드
                ed_staffNm.setValue(rtnList[3]);	//사원명
            } else {
                ed_staffNo.setValue("");	//사원코드
                ed_staffNm.setValue("");	//사원명
            }

        break;;

    }	
}

