//-------------------------------------------------------------------------
// 조회조건 필드 Clear
//-------------------------------------------------------------------------
scwin.f_FieldClear = function () {
    $c.gus.cfInitObjects(condTable,null);
    var sCurrDate = scwin.vQryStDt;
    var sEndDate = scwin.vQryStDt.toDate("YYYYMMDD").after(0,0,14).format("YYYYMMDD");


    ica_inqStDt.setValue(scwin.vQryStDt);
    ica_inqEndDt.setValue(sEndDate);
}

