scwin.f_buttonEnableDisable = function (val){

	if(val == 'E'){
		$c.gus.cfEnableObj(btn_Save,true);      
	}else{
		$c.gus.cfEnableObj(btn_Save,false);
	} 

}

scwin.udc_staffNo_onclickEvent = function (e) {
    scwin.f_openCommonPopUp(1, ed_staffNo.getValue(), ed_staffNm.getValue(), 'F', 'F');
};

scwin.udc_staffNo_onviewchangeCodeEvent = function (info) {
    scwin.f_chkOpenCommonPopUp(ed_staffNo, ed_staffNm, 1);
};

scwin.udc_staffNo_onviewchangeNameEvent = function (info) {
    scwin.f_chkOpenCommonPopUp(ed_staffNm, ed_staffNo, 1, false);
};

scwin.sbm_save_submitdone = function (e) {
    if(e.responseJSON.resultDataSet[0].Code == 0) {
        $c.win.alert(MSG_CM_INF_001);	// 성공적으로 저장하였습니다
        scwin.f_buttonEnableCheck();
    }
};

scwin.ica_inqStDt_onblur = function (e) {
	var sStDate = ica_inqStDt.getValue();
    var sEndDate = sStDate.toDate("YYYYMMDD").after(0,0,14).format("YYYYMMDD");
	ica_inqEndDt.setValue(sEndDate);

	scwin.f_headerSetting(sStDate);
};

scwin.gr_results1_onscrollx = function () {
    gr_results2.setScrollLeft(gr_results1.getScrollLeft());
    gr_results3.setScrollLeft(gr_results1.getScrollLeft());
};

scwin.gr_results1_onscrolly = function () {
    gr_results2.setScrollTop(gr_results1.getScrollTop());
    gr_results3.setScrollTop(gr_results1.getScrollTop());
};

scwin.gr_results3_oncellclick = function (rowIndex, columnIndex, columnId) {
	var bEdit = false;

	var welsalCls = ds_results3.getCellData(rowIndex,"welsalCls");

    gr_results3.setCellReadOnly(rowIndex, "welsalCls", true);

	if(welsalCls =="조식"||welsalCls =="석식"||welsalCls =="야식"||welsalCls =="중식"||welsalCls =="교통비" || welsalCls =="특근비"){

		gr_results3.setCellReadOnly(rowIndex, "dCntAmt1", true);
        gr_results3.setCellReadOnly(rowIndex, "dCntAmt2", true);
        gr_results3.setCellReadOnly(rowIndex, "dCntAmt3", true);        
        gr_results3.setCellReadOnly(rowIndex, "dCntAmt4", true);        
        gr_results3.setCellReadOnly(rowIndex, "dCntAmt5", true);        
        gr_results3.setCellReadOnly(rowIndex, "dCntAmt6", true);        
        gr_results3.setCellReadOnly(rowIndex, "dCntAmt7", true);        
        gr_results3.setCellReadOnly(rowIndex, "dCntAmt8", true);        
        gr_results3.setCellReadOnly(rowIndex, "dCntAmt9", true);        
        gr_results3.setCellReadOnly(rowIndex, "dCntAmt10",true);        
        gr_results3.setCellReadOnly(rowIndex, "dCntAmt11",true);        
        gr_results3.setCellReadOnly(rowIndex, "dCntAmt12",true);        
        gr_results3.setCellReadOnly(rowIndex, "dCntAmt13",true);        
        gr_results3.setCellReadOnly(rowIndex, "dCntAmt14",true);        
        gr_results3.setCellReadOnly(rowIndex, "dCntAmt15",true);

        return;        	


	}

    var Colid = gr_results3.getColumnID(columnIndex);
    var vColIdCnt = Colid.substring(7,Colid.length);

	for(var i=0; i < ds_results1.getRowCount(); i++){
	    var vColId = "";
    	vColId = "ddRslts"+ vColIdCnt;
    	if(ds_results1.getCellData(i,vColId).trim() != ""){
    	    bEdit = true;
    		break;
    	}
    }

	for(var j=0; j < ds_results2.getRowCount(); j++){
		var vColId = "";
		vColId = "ddRslts"+vColIdCnt;
    	if(ds_results2.getCellData(j,vColId).trim() != "" ){
    		bEdit = true;
    		break;
    	}
    }

	if(bEdit){
        gr_results3.setColumnReadOnly(Colid, false);
	}else{
		$c.win.alert("작업실적이 없으므로 복리후생비를 입력할 수 없습니다.");
		gr_results3.setColumnReadOnly(Colid, true);

	}
};

scwin.btn_search_onclick = function (e) {
    scwin.f_Retrieve();
};

scwin.btn_init_onclick = function (e) {
    scwin.f_FieldClear();
};

scwin.btn_Save_onclick = function (e) {
    scwin.f_save();
};

scwin.ds_results1_ondataload = function () {
    spa_cnt1.setValue( ds_results1.getRowCount());
};

scwin.ds_results2_ondataload = function () {
    spa_cnt2.setValue( ds_results2.getRowCount());
};

scwin.ds_results3_ondataload = function () {
    spa_cnt3.setValue( ds_results3.getRowCount());
};

scwin.sbm_search_submitdone = function (e) {

    for(var i = 0; i < ds_results1.getRowCount(); i++){
        ds_results1.setCellData(i, "row", i+1);
    }
    for(var i = 0; i < ds_results2.getRowCount(); i++){
        ds_results2.setCellData(i, "row", i+1);
    }

    scwin.f_buttonEnableCheck();

    ica_inqStDt.focus();
};
